public class RuntimeInfo {
    public static void main(String[] args) {
        // JRE version
        System.out.println("Java version : " + System.getProperty("java.version"));
        System.out.println("JRE home     : " + System.getProperty("java.home"));
        System.out.println("Vendor       : " + System.getProperty("java.vendor"));

        // Module system: list boot layer modules
        ModuleLayer.boot().modules().stream()
            .map(Module::getName)
            .sorted()
            .forEach(System.out::println);
    }
}

import java.nio.file.Files;
import java.nio.file.Path;

public class JdkOrJre {
    public static void main(String[] args) {
        String javaHome = System.getProperty("java.home");
        // In JDK: javac lives at $JAVA_HOME/bin/javac
        // In a custom JRE built with jlink: javac is absent
        boolean hasCompiler = Files.exists(Path.of(javaHome, "bin", "javac"));
        System.out.println(hasCompiler ? "Running inside a JDK" : "Running inside a JRE");
    }
}

