import java.nio.file.*;
import java.io.IOException;
import java.util.List;

public class NioExample {
    public static void main(String[] args) throws IOException {
        Path file = Path.of("/tmp/demo.txt");

        // Write string atomically
        Files.writeString(file, "Hello from JRE NIO\n",
                StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING);

        // Read all lines
        List<String> lines = Files.readAllLines(file);
        lines.forEach(System.out::println);

        // Walk a directory tree
        try (var stream = Files.walk(Path.of("/tmp"))) {
            stream.filter(Files::isRegularFile)
                  .forEach(System.out::println);
        }
    }
}

import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicLong;

public class ConcurrencyExample {
    private static final AtomicLong counter = new AtomicLong(0);

    public static void main(String[] args) throws Exception {
        // Fixed thread pool
        ExecutorService pool = Executors.newFixedThreadPool(4);
        Future<Long> f1 = pool.submit(() -> sumRange(1, 500_000));
        Future<Long> f2 = pool.submit(() -> sumRange(500_001, 1_000_000));
        long total = f1.get() + f2.get();
        System.out.println("Sum: " + total);
        pool.shutdown();

        // Virtual threads (Java 21) — one per task, no pool needed
        try (var executor = Executors.newVirtualThreadPerTaskExecutor()) {
            for (int i = 0; i < 10_000; i++) {
                executor.submit(() -> counter.incrementAndGet());
            }
        }
        System.out.println("Counter: " + counter.get());
    }

    static long sumRange(long start, long end) {
        long sum = 0;
        for (long i = start; i <= end; i++) sum += i;
        return sum;
    }
}

import java.lang.management.*;

public class JreInspector {
    public static void main(String[] args) {
        // Heap memory usage
        MemoryMXBean mem = ManagementFactory.getMemoryMXBean();
        MemoryUsage heap = mem.getHeapMemoryUsage();
        System.out.printf("Heap: %d MB used / %d MB max%n",
            heap.getUsed() >> 20, heap.getMax() >> 20);

        // GC statistics per collector
        ManagementFactory.getGarbageCollectorMXBeans().forEach(gc ->
            System.out.printf("GC [%s]: %d collections, %d ms total%n",
                gc.getName(), gc.getCollectionCount(), gc.getCollectionTime()));

        // Thread count
        ThreadMXBean threads = ManagementFactory.getThreadMXBean();
        System.out.printf("Threads: %d live, %d peak%n",
            threads.getThreadCount(), threads.getPeakThreadCount());

        // CPU cores — drives thread-pool sizing decisions
        int cores = Runtime.getRuntime().availableProcessors();
        System.out.println("CPU cores visible to JVM: " + cores);
    }
}
